      "keystrokes": "cat > /app/mystery.c <<'CEOF'
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {float x,y,z;} Vec;
typedef struct {Vec o,d;} Ray;

static Vec vadd(Vec a,Vec b){return (Vec){a.x+b.x,a.y+b.y,a.z+b.z};}
static Vec vsub(Vec a,Vec b){return (Vec){a.x-b.x,a.y-b.y,a.z-b.z};}
static Vec vmul(Vec a,float s){return (Vec){a.x*s,a.y*s,a.z*s};}
static float vdot(Vec a,Vec b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static float vlen(Vec a){return sqrtf(a.x*a.x+a.y*a.y+a.z*a.z);}
static Vec vnorm(Vec a){float l=vlen(a);return (Vec){a.x/l,a.y/l,a.z/l};}

static int sphere_intersect(Ray r, Vec c, float rad, float *t, Vec *n){
  Vec oc=vsub(r.o,c);
  float b=vdot(oc,r.d);
  float cc=vdot(oc,oc)-rad*rad;
  float d=b*b-cc;
  if(d<0)return 0;
  float s=sqrtf(d);
  float t0=-b-s;
  if(t0>1e-4f){*t=t0;*n=vnorm(vsub(vadd(r.o,vmul(r.d,t0)),c));return 1;}
  float t1=-b+s;
  if(t1>1e-4f){*t=t1;*n=vnorm(vsub(vadd(r.o,vmul(r.d,t1)),c));return 1;}
  return 0;
}

static int plane_intersect(Ray r, float y, float *t){
  if(fabsf(r.d.y)<1e-4f)return 0;
  float tt=(y-r.o.y)/r.d.y;
  if(tt>1e-4f){*t=tt;return 1;}
  return 0;
}

static float hash(float x){
  int i=(int)floorf(x);
  float f=x-(float)i;
  float h=sinf((float)i*12.9898f)*43758.5453f;
  return h-(float)floorf(h);
}

static float noise2d(float x,float y){
  float xi=floorf(x), yi=floorf(y);
  float xf=x-xi, yf=y-yi;
  float a=hash(xi+yi*57.0f);
  float b=hash(xi+1.0f+yi*57.0f);
  float c=hash(xi+(yi+1.0f)*57.0f);
  float d=hash(xi+1.0f+(yi+1.0f)*57.0f);
  float u=xf*xf*(3.0f-2.0f*xf);
  float v=yf*yf*(3.0f-2.0f*yf);
  return a*(1.0f-u)*(1.0f-v)+b*u*(1.0f-v)+c*(1.0f-u)*v+d*u*v;
}

static Vec sky_color(Vec d){
  float t=0.5f*(d.y+1.0f);
  Vec sky={0.5f,0.7f,1.0f};
  Vec horizon={1.0f,1.0f,1.0f};
  Vec c=vadd(vmul(horizon,1.0f-t),vmul(sky,t));
  return c;
}

static int is_in_shadow(Vec p, Vec ldir){
  Ray sr;
  sr.o=p;
  sr.d=ldir;
  float t;
  Vec n;
  Vec sc={-0.5f,-5.0f,1.0f};
  if(sphere_intersect(sr,sc,4.0f,&t,&n))return 1;
  return 0;
}

static Vec trace(Ray r, int depth){
  float t;
  Vec n;
  Vec sc={-0.5f,-5.0f,1.0f};
  if(sphere_intersect(r,sc,4.0f,&t,&n)){
    Vec p=vadd(r.o,vmul(r.d,t));
    Vec ldir=vnorm((Vec){1.0f,1.0f,-1.0f});
    float diff=fmaxf(0.0f,vdot(n,ldir));
    if(is_in_shadow(vadd(p,vmul(n,0.001f)),ldir))diff=0.0f;
    Vec base={0.8f,0.2f,0.2f};
    Vec col=vmul(base,0.2f+0.8f*diff);
    if(depth>0){
      Vec refl=vsub(r.d,vmul(n,2.0f*vdot(r.d,n)));
      Ray rr;rr.o=vadd(p,vmul(n,0.001f));rr.d=vnorm(refl);
      Vec rc=trace(rr,depth-1);
      col=vadd(vmul(col,0.7f),vmul(rc,0.3f));
    }
    return col;
  }
  float pt;
  if(plane_intersect(r,-1.5f,&pt)){
    Vec p=vadd(r.o,vmul(r.d,pt));
    float h=noise2d(p.x*0.2f,p.z*0.2f);
    Vec base={0.6f,0.6f,0.6f};
    if(h>0.5f)base=(Vec){0.4f,0.4f,0.4f};
    Vec ldir=vnorm((Vec){1.0f,1.0f,-1.0f});
    float diff=fmaxf(0.0f,vdot((Vec){0.0f,1.0f,0.0f},ldir));
    if(is_in_shadow(vadd(p,(Vec){0.0f,0.001f,0.0f}),ldir))diff=0.0f;
    Vec col=vmul(base,0.2f+0.8f*diff);
    return col;
  }
  return sky_color(vnorm(r.d));
}

int main(){
  int W=800,H=600;
  fprintf(stderr,"Creating high-resolution image: %dx%d\n",W,H);
  fwrite("This will be downsampled with ffmpeg after rendering\n",1,53,stderr);
  fprintf(stderr,"Rendering high-resolution image...\n");
  Vec ***img=malloc(H*sizeof(Vec**));
  for(int y=0;y<H;y++)img[y]=malloc(W*sizeof(Vec*));
  for(int y=0;y<H;y++){
    img[y]=malloc(W*sizeof(Vec*));
    for(int x=0;x<W;x++)img[y][x]=malloc(sizeof(Vec));
    float prog=(float)y/(float)H*100.0f;
    fprintf(stderr,"\rProgress: %.1f%%",prog);
    for(int x=0;x<W;x++){
      float u=(float)x/(float)W;
      float v=(float)y/(float)H;
      u=2.0f*u-1.0f;
      v=1.0f-2.0f*v;
      u*=8.0f/6.0f;
      Ray r;
      r.o=(Vec){0.0f,0.0f,0.0f};
      r.d=vnorm((Vec){u,v,-1.0f});
      Vec c=trace(r,2);
      img[y][x]->x=c.x;
      img[y][x]->y=c.y;
      img[y][x]->z=c.z;
    }
  }
  fprintf(stderr,"\nRendering complete\n");
  FILE *f=fopen("image.ppm","w");
  fprintf(f,"P3\n%d %d\n255\n",W,H);
  for(int y=0;y<H;y++){
    for(int x=0;x<W;x++){
      fprintf(f,"%d %d %d\n",
        (int)(img[y][x]->x*255.99f),
        (int)(img[y][x]->y*255.99f),
        (int)(img[y][x]->z*255.99f));
    }
  }
  fclose(f);
  fprintf(stderr,"Wrote image to image.ppm\nDone.\n");
  for(int y=0;y<H;y++){for(int x=0;x<W;x++)free(img[y][x]);free(img[y]);}
  free(img);
  return 0;
}
